import UIKit
import CryptoSwift

class WalletManager {
    // MARK: - Private properties
    
    private let privateKey: Data?
    
    // MARK: - Initializers
    
    init() {
        self.privateKey = generatePrivateKey()
    }
    
    convenience init(privateKey: Data) {
        self.init()
        
        self.privateKey = privateKey
    }
    
    // MARK: - Methods
    
    func generatePrivateKey() -> Data? {
        let keyData = try? CryptoSwift.generate(keySizeInBytes: 32, secureRandom: SecureRandom())
        
        return keyData
    }
    
    func signTransaction(_ transaction: Transaction) -> Signature? {
        guard let privateKey = self.privateKey else {
            print("Failed to sign transaction with invalid private key")
            return nil
        }
        
        let signature = CryptoSwift.sign(privateKey: privateKey, data: transaction.data, signatureType: .secp256k1)
        
        return Signature(rawRepresentation: signature)
    }
    
    func sendTransaction(_ transaction: Transaction) -> Bool {
        let url = URL(string: "https://blockchain.info/api/send-tx")!
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        
        do {
            let json = try JSONEncoder().encode(transaction)
            request.httpBody = json
            
            URLSession.shared.dataTask(with: request) { (data, response, error) in
                if let data = data, let response = response as? HTTPURLResponse {
                    // Check the status code of the response
                    switch response.statusCode {
                        case 200:
                            print("Transaction sent successfully")
                        default:
                            print("Failed to send transaction with status code \(response.statusCode)")
                    }
                } else {
                    print("Failed to send transaction due to error: \(error?.localizedDescription ?? "No error description")")
                }
            }.resume()
            
            return true
        } catch {
            print("Failed to send transaction with error: \(error.localizedDescription)")
            return false
        }
    }
}